    {"title": "Construct Binary Tree from Preorder and Inorder", "description": "Given preorder and inorder traversal arrays, construct the binary tree.", "requirements": "Input: lists preorder, inorder. Output: root node. Use recursion with index maps."},
    {"title": "Construct Binary Tree from Inorder and Postorder", "description": "Given inorder and postorder traversal arrays, construct the binary tree.", "requirements": "Input: lists inorder, postorder. Output: root node. Last element of postorder is root."},
    {"title": "Populating Next Right Pointers", "description": "Populate each next pointer to point to its next right node in a perfect binary tree.", "requirements": "Input: root node. Output: root with next pointers set. O(1) extra space using level-by-level traversal."},
    {"title": "Flatten Binary Tree to Linked List", "description": "Flatten a binary tree into a linked list in-place (using right pointers, preorder).", "requirements": "Input: root node. Output: void. Use Morris traversal or reverse postorder."},
    {"title": "Binary Search Tree Iterator", "description": "Implement an iterator over a BST that returns elements in ascending order.", "requirements": "next() and hasNext() should run in O(1) average time and O(h) space where h is tree height. Use a stack."},
    {"title": "Kth Smallest Element in BST", "description": "Given the root of a BST and integer k, return the kth smallest value.", "requirements": "Input: root node, integer k. Output: integer. In-order traversal gives sorted order."},
    {"title": "Validate Binary Search Tree", "description": "Given the root of a binary tree, determine if it is a valid BST.", "requirements": "Input: root node. Output: boolean. Use min/max bounds in recursive calls."},
    {"title": "Lowest Common Ancestor of BST", "description": "Given a BST and two nodes p and q, find their lowest common ancestor.", "requirements": "Input: root, nodes p and q. Output: LCA node. Use BST property to navigate."},
    {"title": "Lowest Common Ancestor of Binary Tree", "description": "Given a binary tree (not BST) and two nodes, find their lowest common ancestor.", "requirements": "Input: root, nodes p and q. Output: LCA node. Use recursive DFS."},
    {"title": "Count Good Nodes in Binary Tree", "description": "A node X is good if in the path from root to X there are no nodes with a value greater than X. Count good nodes.", "requirements": "Input: root node. Output: integer. DFS tracking max value seen so far."},
    # --- MEDIUM 51-100 ---
    {"title": "Number of Islands", "description": "Given a 2D grid of '1's (land) and '0's (water), count the number of islands.", "requirements": "Input: 2D list grid. Output: integer. Use DFS or BFS, mark visited cells."},
    {"title": "Max Area of Island", "description": "Given a binary matrix, find the maximum area of an island (connected 1s).", "requirements": "Input: 2D list grid. Output: integer. DFS/BFS to compute area of each island."},
    {"title": "Clone Graph", "description": "Given a reference to a node in a connected undirected graph, return a deep copy of the graph.", "requirements": "Input: node. Output: cloned node. Use BFS/DFS with a hashmap to track cloned nodes."},
    {"title": "Pacific Atlantic Water Flow", "description": "Find all cells in a matrix where water can flow to both the Pacific and Atlantic oceans.", "requirements": "Input: 2D list heights. Output: list of [row, col]. BFS/DFS from ocean borders inward."},
    {"title": "Surrounded Regions", "description": "Given a board with 'X' and 'O', capture all regions surrounded by 'X' (flip 'O' to 'X'), except those connected to the border.", "requirements": "Input: 2D list board. Output: void. DFS/BFS from border 'O' cells to mark safe ones."},
    {"title": "Rotting Oranges", "description": "Given a grid with fresh (1) and rotten (2) oranges, find the minimum minutes until no fresh orange remains, or -1.", "requirements": "Input: 2D list grid. Output: integer. Multi-source BFS from all rotten oranges."},
    {"title": "Walls and Gates", "description": "Fill each empty room with the distance to its nearest gate. Walls=-1, Gates=0, Empty=INF.", "requirements": "Input: 2D list rooms. Output: void (in-place). Multi-source BFS from all gates."},
    {"title": "Course Schedule", "description": "Given n courses and prerequisites, determine if you can finish all courses (detect cycle in directed graph).", "requirements": "Input: integer n, list prerequisites. Output: boolean. Topological sort (Kahn's or DFS)."},
    {"title": "Course Schedule II", "description": "Return the ordering of courses to finish all of them, or empty array if impossible.", "requirements": "Input: integer n, list prerequisites. Output: list. Topological sort using BFS (Kahn's algorithm)."},
    {"title": "Graph Valid Tree", "description": "Given n nodes and a list of undirected edges, determine if they form a valid tree.", "requirements": "Input: integer n, list edges. Output: boolean. A tree has n-1 edges and is connected (no cycles)."},
    {"title": "Number of Connected Components in Undirected Graph", "description": "Given n nodes and edges, count the number of connected components.", "requirements": "Input: integer n, list edges. Output: integer. Use Union-Find or DFS/BFS."},
    {"title": "Redundant Connection", "description": "Given a tree with one extra edge, find the redundant edge that creates a cycle.", "requirements": "Input: list edges. Output: edge [u, v]. Use Union-Find."},
    {"title": "Accounts Merge", "description": "Given a list of accounts [name, email1, email2, ...], merge accounts that share an email.", "requirements": "Input: list accounts. Output: merged list. Use Union-Find or DFS on email graph."},
    {"title": "Word Ladder", "description": "Find the length of the shortest transformation sequence from beginWord to endWord, changing one letter at a time.", "requirements": "Input: strings beginWord, endWord, list wordList. Output: integer. BFS. Return 0 if no path."},
    {"title": "Open the Lock", "description": "Given a lock with 4 wheels (0000-9999), deadends, and a target, find minimum turns to reach target.", "requirements": "Input: list deadends, string target. Output: integer. BFS from '0000'."},
    {"title": "Minimum Height Trees", "description": "For a tree of n nodes, find all roots that minimize the height.", "requirements": "Input: integer n, list edges. Output: list of root nodes. Iteratively remove leaf nodes."},
    {"title": "Reconstruct Itinerary", "description": "Given a list of airline tickets [from, to], reconstruct the itinerary starting from 'JFK' using all tickets.", "requirements": "Input: list tickets. Output: list of airports. Use Hierholzer's algorithm (DFS with backtracking)."},
    {"title": "Find Eventual Safe States", "description": "In a directed graph, a node is safe if every path from it leads to a terminal node. Return all safe nodes.", "requirements": "Input: 2D list graph. Output: sorted list of safe nodes. DFS with coloring (white/gray/black)."},
    {"title": "Combination Sum", "description": "Given an array of distinct integers and a target, find all unique combinations that sum to target (can reuse elements).", "requirements": "Input: list candidates, integer target. Output: list of combinations. Backtracking."},
    {"title": "Combination Sum II", "description": "Given a collection of integers (may have duplicates) and a target, find all unique combinations that sum to target (each number used once).", "requirements": "Input: list candidates, integer target. Output: list of combinations. Sort and skip duplicates."},
    {"title": "Permutations", "description": "Given an array of distinct integers, return all possible permutations.", "requirements": "Input: list nums. Output: list of permutations. Backtracking with swap or used-array."},
    {"title": "Permutations II", "description": "Given a collection of numbers that might contain duplicates, return all unique permutations.", "requirements": "Input: list nums. Output: list of unique permutations. Sort and skip duplicates in backtracking."},
    {"title": "Subsets", "description": "Given an integer array of unique elements, return all possible subsets (the power set).", "requirements": "Input: list nums. Output: list of subsets. Backtracking or bit manipulation."},
    {"title": "Subsets II", "description": "Given an integer array that may contain duplicates, return all possible unique subsets.", "requirements": "Input: list nums. Output: list of unique subsets. Sort and skip duplicates."},
    {"title": "Letter Combinations of a Phone Number", "description": "Given a string of digits 2-9, return all possible letter combinations.", "requirements": "Input: string digits. Output: list of strings. Backtracking with phone keypad mapping."},
    {"title": "Generate Parentheses", "description": "Given n pairs of parentheses, generate all combinations of well-formed parentheses.", "requirements": "Input: integer n. Output: list of strings. Backtracking tracking open/close counts."},
    {"title": "Palindrome Partitioning", "description": "Given a string, partition it such that every substring is a palindrome. Return all possible partitions.", "requirements": "Input: string s. Output: list of partitions. Backtracking with palindrome check."},
    {"title": "N-Queens", "description": "Place n queens on an n x n chessboard so no two queens attack each other. Return all distinct solutions.", "requirements": "Input: integer n. Output: list of board configurations. Backtracking with column/diagonal tracking."},
    {"title": "Sudoku Solver", "description": "Write a program to solve a Sudoku puzzle by filling the empty cells.", "requirements": "Input: 9x9 2D list board. Output: void (in-place). Backtracking with constraint checking."},
    {"title": "Word Search II", "description": "Given a board and a list of words, find all words that exist in the board.", "requirements": "Input: 2D list board, list words. Output: list of found words. Build a Trie then DFS."},
    {"title": "Decode Ways", "description": "A message encoded as digits can be decoded (1->A, 2->B, ..., 26->Z). Count the number of ways to decode a string.", "requirements": "Input: string s. Output: integer. Dynamic programming. Handle leading zeros."},
    {"title": "Unique Paths", "description": "A robot on an m x n grid can only move right or down. Count the number of unique paths to the bottom-right corner.", "requirements": "Input: integers m, n. Output: integer. DP or combinatorics (C(m+n-2, m-1))."},
    {"title": "Unique Paths II", "description": "Same as Unique Paths but with obstacles (1=obstacle, 0=free). Count paths avoiding obstacles.", "requirements": "Input: 2D list obstacleGrid. Output: integer. DP with obstacle check."},
    {"title": "Minimum Path Sum", "description": "Given an m x n grid of non-negative integers, find a path from top-left to bottom-right that minimizes the sum.", "requirements": "Input: 2D list grid. Output: integer. DP in-place."},
    {"title": "Triangle", "description": "Given a triangle array, find the minimum path sum from top to bottom (each step moves to adjacent number below).", "requirements": "Input: list of lists triangle. Output: integer. Bottom-up DP with O(n) space."},
    {"title": "Maximum Subarray", "description": "Given an integer array, find the contiguous subarray with the largest sum.", "requirements": "Input: list nums. Output: integer. Kadane's algorithm O(n)."},
    {"title": "Maximum Product Subarray", "description": "Given an integer array, find the contiguous subarray with the largest product.", "requirements": "Input: list nums. Output: integer. Track both max and min products (negatives can flip)."},
    {"title": "House Robber", "description": "Given an array of house values, find the maximum amount you can rob without robbing adjacent houses.", "requirements": "Input: list nums. Output: integer. DP: dp[i] = max(dp[i-1], dp[i-2] + nums[i])."},
    {"title": "House Robber II", "description": "Houses are arranged in a circle. Find the maximum amount you can rob without robbing adjacent houses.", "requirements": "Input: list nums. Output: integer. Run House Robber on [0..n-2] and [1..n-1], take max."},
    {"title": "Coin Change", "description": "Given coins of different denominations and an amount, find the fewest coins needed to make up that amount.", "requirements": "Input: list coins, integer amount. Output: integer, or -1 if impossible. DP bottom-up."},
    {"title": "Coin Change II", "description": "Given coins and an amount, return the number of combinations that make up that amount.", "requirements": "Input: list coins, integer amount. Output: integer. DP unbounded knapsack."},
    {"title": "Longest Increasing Subsequence", "description": "Given an integer array, return the length of the longest strictly increasing subsequence.", "requirements": "Input: list nums. Output: integer. O(n log n) using patience sorting / binary search."},
    {"title": "Longest Common Subsequence", "description": "Given two strings, return the length of their longest common subsequence.", "requirements": "Input: strings text1, text2. Output: integer. 2D DP table."},
    {"title": "Edit Distance", "description": "Given two strings word1 and word2, return the minimum number of operations (insert, delete, replace) to convert word1 to word2.", "requirements": "Input: strings word1, word2. Output: integer. 2D DP (Levenshtein distance)."},
    {"title": "Partition Equal Subset Sum", "description": "Given an integer array, determine if it can be partitioned into two subsets with equal sum.", "requirements": "Input: list nums. Output: boolean. 0/1 knapsack DP. Target = total_sum / 2."},
    {"title": "Target Sum", "description": "Given an integer array and target, assign '+' or '-' to each number. Count ways to reach the target.", "requirements": "Input: list nums, integer target. Output: integer. DP or DFS with memoization."},
    {"title": "Ones and Zeroes", "description": "Given an array of binary strings and integers m and n, find the largest subset with at most m 0s and n 1s.", "requirements": "Input: list strs, integers m, n. Output: integer. 2D 0/1 knapsack DP."},
    {"title": "Interleaving String", "description": "Given strings s1, s2, s3, determine if s3 is formed by interleaving s1 and s2.", "requirements": "Input: strings s1, s2, s3. Output: boolean. 2D DP."},
    {"title": "Distinct Subsequences", "description": "Given strings s and t, return the number of distinct subsequences of s which equals t.", "requirements": "Input: strings s, t. Output: integer. 2D DP."},
    {"title": "Regular Expression Matching", "description": "Implement regular expression matching with '.' (any char) and '*' (zero or more of preceding).", "requirements": "Input: strings s, p. Output: boolean. 2D DP."},
    {"title": "Wildcard Matching", "description": "Implement wildcard pattern matching with '?' (any single char) and '*' (any sequence including empty).", "requirements": "Input: strings s, p. Output: boolean. 2D DP."},
    # --- MEDIUM 101-150 ---
    {"title": "Implement Trie (Prefix Tree)", "description": "Implement a trie with insert, search, and startsWith methods.", "requirements": "All operations O(m) where m is key length. Use a TrieNode class with children dict and is_end flag."},
    {"title": "Design Add and Search Words Data Structure", "description": "Design a data structure that supports addWord and search (with '.' wildcard matching any letter).", "requirements": "Use a Trie. Search with '.' requires DFS through all children."},
    {"title": "Word Break", "description": "Given a string and a dictionary, determine if the string can be segmented into dictionary words.", "requirements": "Input: string s, list wordDict. Output: boolean. DP with set lookup."},
    {"title": "Word Break II", "description": "Given a string and dictionary, return all possible sentences formed by segmenting the string.", "requirements": "Input: string s, list wordDict. Output: list of strings. Backtracking with memoization."},
    {"title": "Maximum Depth of N-ary Tree", "description": "Given the root of an N-ary tree, return its maximum depth.", "requirements": "Input: root node. Output: integer. DFS or BFS."},
    {"title": "N-ary Tree Level Order Traversal", "description": "Given the root of an N-ary tree, return the level order traversal of its nodes' values.", "requirements": "Input: root node. Output: list of lists. BFS with queue."},
    {"title": "Serialize and Deserialize Binary Tree", "description": "Design an algorithm to serialize and deserialize a binary tree.", "requirements": "Serialize: tree -> string. Deserialize: string -> tree. Use BFS or preorder with null markers."},
    {"title": "Binary Tree Right Side View", "description": "Given the root of a binary tree, return the values visible from the right side.", "requirements": "Input: root node. Output: list. BFS level order, take last element of each level."},
    {"title": "Sum Root to Leaf Numbers", "description": "Given a binary tree where each root-to-leaf path represents a number, return the total sum.", "requirements": "Input: root node. Output: integer. DFS tracking current number."},
    {"title": "Path Sum II", "description": "Find all root-to-leaf paths where the sum equals targetSum.", "requirements": "Input: root node, integer targetSum. Output: list of paths. DFS with backtracking."},
    {"title": "Path Sum III", "description": "Count the number of paths in a binary tree that sum to a given target (path doesn't need to start/end at root/leaf).", "requirements": "Input: root node, integer targetSum. Output: integer. Use prefix sum + DFS."},
    {"title": "Diameter of Binary Tree", "description": "Given the root of a binary tree, return the length of the diameter (longest path between any two nodes).", "requirements": "Input: root node. Output: integer. DFS tracking max left+right depth at each node."},
    {"title": "Binary Tree Maximum Path Sum", "description": "Find the maximum path sum in a binary tree (path can start and end at any node).", "requirements": "Input: root node. Output: integer. DFS returning max gain, track global max."},
    {"title": "House Robber III", "description": "Houses are arranged in a binary tree. Rob maximum without robbing directly-linked houses.", "requirements": "Input: root node. Output: integer. DFS returning (rob_root, skip_root) pair."},
    {"title": "Delete Node in BST", "description": "Given a root of a BST and a key, delete the node with that key and return the root.", "requirements": "Input: root node, integer key. Output: new root. Handle 3 cases: no child, one child, two children."},
    {"title": "Insert into BST", "description": "Given the root of a BST and a value, insert the value and return the root.", "requirements": "Input: root node, integer val. Output: new root. Recursively find correct position."},
    {"title": "Search in BST", "description": "Given the root of a BST and a value, return the subtree rooted at the node with that value, or null.", "requirements": "Input: root node, integer val. Output: node or None. Use BST property."},
    {"title": "Trim BST", "description": "Given the root of a BST and range [low, high], trim the tree so all values are within the range.", "requirements": "Input: root node, integers low, high. Output: new root. Recursive trimming."},
    {"title": "Convert Sorted Array to BST", "description": "Given a sorted array, convert it to a height-balanced BST.", "requirements": "Input: sorted list nums. Output: root node. Use middle element as root recursively."},
    {"title": "Convert Sorted List to BST", "description": "Given a sorted linked list, convert it to a height-balanced BST.", "requirements": "Input: head node. Output: root node. Find middle using slow/fast pointers."},
    {"title": "Balance a Binary Search Tree", "description": "Given the root of a BST, return a balanced BST with the same node values.", "requirements": "Input: root node. Output: new root. In-order traversal to get sorted array, then build balanced BST."},
    {"title": "All Elements in Two Binary Search Trees", "description": "Given the roots of two BSTs, return a sorted list of all elements from both trees.", "requirements": "Input: two root nodes. Output: sorted list. In-order traversal of both, then merge."},
    {"title": "Recover Binary Search Tree", "description": "Two nodes of a BST are swapped by mistake. Recover the tree without changing its structure.", "requirements": "Input: root node. Output: void. In-order traversal to find the two swapped nodes."},
    {"title": "Unique Binary Search Trees", "description": "Given n, return the number of structurally unique BSTs with values 1..n (Catalan number).", "requirements": "Input: integer n. Output: integer. DP: G(n) = sum of G(i-1)*G(n-i) for i=1..n."},
    {"title": "Unique Binary Search Trees II", "description": "Given n, return all structurally unique BSTs with values 1..n.", "requirements": "Input: integer n. Output: list of root nodes. Recursive generation with memoization."},
    {"title": "Merge k Sorted Lists", "description": "Merge k sorted linked lists and return the merged sorted list.", "requirements": "Input: list of head nodes. Output: head of merged list. Use a min-heap for O(n log k)."},
    {"title": "Find Median from Data Stream", "description": "Design a data structure that supports adding numbers and finding the median.", "requirements": "addNum: O(log n). findMedian: O(1). Use two heaps: max-heap for lower half, min-heap for upper half."},
    {"title": "Kth Largest Element in a Stream", "description": "Design a class to find the kth largest element in a stream.", "requirements": "Constructor takes k and initial array. add() returns kth largest after adding. Use a min-heap of size k."},
    {"title": "Task Scheduler", "description": "Given tasks and cooldown n, find the minimum intervals needed to execute all tasks.", "requirements": "Input: list tasks, integer n. Output: integer. Greedy with max-heap or math formula."},
    {"title": "Reorganize String", "description": "Given a string, rearrange characters so no two adjacent characters are the same.", "requirements": "Input: string s. Output: rearranged string, or empty string if impossible. Use max-heap."},
    {"title": "K Closest Points to Origin", "description": "Given an array of points, return the k closest to the origin.", "requirements": "Input: list points, integer k. Output: list of k points. Use a max-heap of size k or quickselect."},
    {"title": "Find K Pairs with Smallest Sums", "description": "Given two sorted arrays, find the k pairs (u, v) with the smallest sums.", "requirements": "Input: lists nums1, nums2, integer k. Output: list of pairs. Use a min-heap."},
    {"title": "Sort Characters By Frequency", "description": "Given a string, sort it in decreasing order based on character frequency.", "requirements": "Input: string s. Output: string. Use a max-heap or bucket sort."},
    {"title": "Top K Frequent Words", "description": "Given a list of words and integer k, return the k most frequent words sorted by frequency (ties broken alphabetically).", "requirements": "Input: list words, integer k. Output: list. Use a heap with custom comparator."},
    {"title": "Ugly Number II", "description": "An ugly number has only prime factors 2, 3, 5. Find the nth ugly number.", "requirements": "Input: integer n. Output: integer. DP with three pointers for factors 2, 3, 5."},
    {"title": "Super Ugly Number", "description": "Given an array of primes, find the nth super ugly number (only prime factors from the given list).", "requirements": "Input: integer n, list primes. Output: integer. Use a min-heap."},
    {"title": "Meeting Rooms", "description": "Given an array of meeting time intervals, determine if a person can attend all meetings.", "requirements": "Input: list of [start, end] intervals. Output: boolean. Sort by start, check for overlaps."},
    {"title": "Meeting Rooms II", "description": "Find the minimum number of conference rooms required to hold all meetings.", "requirements": "Input: list of [start, end] intervals. Output: integer. Sort starts/ends separately or use min-heap."},
    {"title": "Non-overlapping Intervals", "description": "Given an array of intervals, find the minimum number of intervals to remove to make the rest non-overlapping.", "requirements": "Input: list intervals. Output: integer. Sort by end time, greedy."},
    {"title": "Merge Intervals", "description": "Given an array of intervals, merge all overlapping intervals.", "requirements": "Input: list intervals. Output: list of merged intervals. Sort by start time."},
    {"title": "Insert Interval", "description": "Given a sorted list of non-overlapping intervals and a new interval, insert and merge if necessary.", "requirements": "Input: list intervals, list newInterval. Output: list. Handle three regions: before, overlap, after."},
    {"title": "Minimum Number of Arrows to Burst Balloons", "description": "Given balloon intervals on x-axis, find minimum arrows to burst all balloons.", "requirements": "Input: list points [xstart, xend]. Output: integer. Sort by end, greedy."},
    {"title": "Queue Reconstruction by Height", "description": "Given people [h, k] (height, number of taller/equal people in front), reconstruct the queue.", "requirements": "Input: list people. Output: list. Sort by height desc (ties by k asc), insert at index k."},
    {"title": "Partition Labels", "description": "Partition a string into as many parts as possible so each letter appears in at most one part.", "requirements": "Input: string s. Output: list of partition sizes. Track last occurrence of each character."},
    {"title": "Jump Game III", "description": "Given an array and start index, you can jump to index+arr[i] or index-arr[i]. Can you reach any index with value 0?", "requirements": "Input: list arr, integer start. Output: boolean. BFS/DFS."},
    {"title": "Minimum Jumps to Reach Home", "description": "A bug can jump forward a or backward b positions, with forbidden positions. Find minimum jumps to reach target.", "requirements": "Input: list forbidden, integers a, b, x. Output: integer. BFS with visited set."},
    {"title": "Evaluate Division", "description": "Given equations A/B = k and queries, evaluate each query or return -1 if unknown.", "requirements": "Input: list equations, list values, list queries. Output: list of doubles. Build weighted graph, BFS/DFS."},
    {"title": "Network Delay Time", "description": "Given a network of n nodes and weighted directed edges, find the time for all nodes to receive a signal from node k.", "requirements": "Input: list times [u,v,w], integers n, k. Output: integer or -1. Dijkstra's algorithm."},
    {"title": "Cheapest Flights Within K Stops", "description": "Find the cheapest price from src to dst with at most k stops.", "requirements": "Input: integer n, list flights [from,to,price], integers src, dst, k. Output: integer or -1. Bellman-Ford or BFS."},
    {"title": "Find the City With the Smallest Number of Neighbors at a Threshold Distance", "description": "Find the city with the fewest reachable cities within distanceThreshold.", "requirements": "Input: integer n, list edges, integer distanceThreshold. Output: integer city. Floyd-Warshall."},
    # --- MEDIUM 151-200 ---
    {"title": "Implement Stack with Increment Operation", "description": "Design a stack with push, pop, and increment(k, val) that adds val to the bottom k elements.", "requirements": "All operations O(1). Use lazy increment with an auxiliary array."},
    {"title": "Design Circular Queue", "description": "Implement a circular queue with enQueue, deQueue, Front, Rear, isEmpty, isFull.", "requirements": "Use a fixed-size array with head and tail pointers."},
    {"title": "Design Circular Deque", "description": "Implement a circular double-ended queue with insertFront, insertLast, deleteFront, deleteLast, getFront, getRear.", "requirements": "Use a fixed-size array with head and tail pointers."},
    {"title": "Maximum Frequency Stack", "description": "Design a stack-like data structure that pops the most frequently occurring element.", "requirements": "push and pop both O(1). Use a frequency map and a map of freq->stack."},
    {"title": "Design Twitter", "description": "Design a simplified Twitter with postTweet, getNewsFeed (10 most recent), follow, and unfollow.", "requirements": "getNewsFeed returns 10 most recent tweets from user and followees. Use a heap."},
    {"title": "Snapshot Array", "description": "Implement a SnapshotArray with set(index, val), snap() returning snap_id, and get(index, snap_id).", "requirements": "Use binary search on stored snapshots per index for efficient get."},
    {"title": "Time Based Key-Value Store", "description": "Design a key-value store that stores multiple values for the same key at different timestamps.", "requirements": "set(key, value, timestamp) and get(key, timestamp) returning value at largest timestamp <= given. Binary search."},
    {"title": "All O'one Data Structure", "description": "Design a data structure with inc(key), dec(key), getMaxKey(), getMinKey() all in O(1).", "requirements": "Use a doubly linked list of buckets by count + two hashmaps."},
    {"title": "Longest Palindromic Substring", "description": "Given a string, return the longest palindromic substring.", "requirements": "Input: string s. Output: string. Expand around center O(n^2) or Manacher's O(n)."},
    {"title": "Palindromic Substrings", "description": "Given a string, count how many substrings are palindromes.", "requirements": "Input: string s. Output: integer. Expand around center for O(n^2)."},
    {"title": "Longest Palindromic Subsequence", "description": "Given a string, find the length of the longest palindromic subsequence.", "requirements": "Input: string s. Output: integer. 2D DP: LPS(s) = LCS(s, reverse(s))."},
    {"title": "Minimum Insertions to Make String Palindrome", "description": "Find the minimum number of insertions to make a string a palindrome.", "requirements": "Input: string s. Output: integer. Answer = len(s) - LPS(s)."},
    {"title": "Shortest Common Supersequence", "description": "Given two strings, find the length of the shortest string that has both as subsequences.", "requirements": "Input: strings str1, str2. Output: integer. SCS = len(s1) + len(s2) - LCS(s1, s2)."},
    {"title": "Minimum ASCII Delete Sum for Two Strings", "description": "Find the minimum sum of ASCII values of deleted characters to make two strings equal.", "requirements": "Input: strings s1, s2. Output: integer. 2D DP similar to edit distance."},
