async def seed():
    async with AsyncSessionLocal() as db:
        # Count existing coding questions per difficulty
        for difficulty, questions in [("easy", EASY_QUESTIONS), ("medium", MEDIUM_QUESTIONS), ("hard", HARD_QUESTIONS)]:
            result = await db.execute(
                select(func.count()).where(
                    ChallengeTask.domain == "coding",
                    ChallengeTask.difficulty == difficulty,
                    ChallengeTask.is_active == True,
                )
            )
            existing = result.scalar()
            to_insert = questions[existing:]
            if not to_insert:
                print(f"[seed] {difficulty}: already has {existing} questions, skipping")
                continue
            for q in to_insert:
                db.add(ChallengeTask(
                    domain="coding",
                    difficulty=difficulty,
                    title=q["title"],
                    description=q["description"],
                    requirements=q.get("requirements", ""),
                    is_active=True,
                ))
            await db.commit()
            print(f"[seed] {difficulty}: inserted {len(to_insert)} questions")


if __name__ == "__main__":
    asyncio.run(seed())
